// AUTO-GENERATED - do not edit by hand.
// Apple .pkpass images (icon required; logo shown top-left), downscaled from the
// production launcher icon assets/images/twofer-icon-1024.png. Base64 PNG bytes,
// decoded at runtime and written into the .pkpass zip + manifest.

const B64: Record<string, string> = {
  "icon.png": "",
  "icon@2x.png": "",
  "icon@3x.png": "",
  "logo.png": "",
  "logo@2x.png": "",
  "logo@3x.png": "",
};

function b64ToBytes(b64: string): Uint8Array {
  const bin = atob(b64);
  const arr = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) arr[i] = bin.charCodeAt(i);
  return arr;
}

/** Filename -> PNG bytes for every image bundled into the .pkpass. */
export function applePassImages(): Record<string, Uint8Array> {
  const out: Record<string, Uint8Array> = {};
  for (const [name, b64] of Object.entries(B64)) out[name] = b64ToBytes(b64);
  return out;
}
